#ifndef RMSNORM_H4096_KERNEL_H_
#define RMSNORM_H4096_KERNEL_H_

#include <cstdint>
#include <cuda_runtime.h>

#ifndef CUDA_CHECK
#define CUDA_CHECK(call)                                                       \
  do {                                                                         \
    cudaError_t _e = (call);                                                   \
    if (_e != cudaSuccess) {                                                   \
      printf("CUDA error %s:%d: %s\n", __FILE__, __LINE__,                     \
             cudaGetErrorString(_e));                                          \
    }                                                                          \
  } while (0)
#endif

// hidden_size fixed to 4096, dtype BF16
void rmsnorm_h4096_launcher(const void* hidden_states_bf16,
                            const void* weight_bf16,
                            void* output_bf16,
                            int64_t batch_size,
                            cudaStream_t stream);

#endif // RMSNORM_H4096_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_bf16.h>
#include <cuda_runtime.h>
#include <stdint.h>

static_assert(sizeof(__nv_bfloat16) == 2, "bf16 size must be 2 bytes");

constexpr int HIDDEN = 4096;
constexpr int THREADS = 256;          // 8 warps
constexpr int ELEMS_PER_THREAD = 16;  // 4096 / 256
constexpr float EPS = 1e-5f;
constexpr float INV_H = 1.0f / 4096.0f;

__device__ __forceinline__ float warp_reduce_sum(float v) {
  unsigned mask = 0xffffffffu;
#pragma unroll
  for (int offset = 16; offset > 0; offset >>= 1) {
    v += __shfl_down_sync(mask, v, offset);
  }
  return v;
}

// Correct block reduction: broadcast the final sum to all threads via shared memory.
__device__ __forceinline__ float block_reduce_sum_256(float v) {
  __shared__ float warp_sums[8]; // 8 warps for 256 threads
  __shared__ float block_sum;

  int lane = threadIdx.x & 31;
  int warp = threadIdx.x >> 5;

  v = warp_reduce_sum(v);
  if (lane == 0) warp_sums[warp] = v;
  __syncthreads();

  float sum = 0.0f;
  if (warp == 0) {
    sum = (lane < 8) ? warp_sums[lane] : 0.0f;
    sum = warp_reduce_sum(sum);
    if (lane == 0) block_sum = sum;
  }
  __syncthreads();
  return block_sum;
}

__global__ void rmsnorm_h4096_kernel(const __nv_bfloat16* __restrict__ x,
                                     const __nv_bfloat16* __restrict__ w,
                                     __nv_bfloat16* __restrict__ y,
                                     int64_t batch_size) {
  int row = (int)blockIdx.x;
  if ((int64_t)row >= batch_size) return;

  int tid = (int)threadIdx.x;
  int base = row * HIDDEN + tid * ELEMS_PER_THREAD;

  const __nv_bfloat16* xptr = x + base;

  // sumsq in fp32
  float sumsq = 0.0f;
#pragma unroll
  for (int i = 0; i < ELEMS_PER_THREAD; i += 2) {
    // base is 32B aligned; i is even -> 4B aligned for bf16x2
    __nv_bfloat162 bx = *reinterpret_cast<const __nv_bfloat162*>(xptr + i);
    float2 fx = __bfloat1622float2(bx);
    sumsq = fmaf(fx.x, fx.x, sumsq);
    sumsq = fmaf(fx.y, fx.y, sumsq);
  }

  float total = block_reduce_sum_256(sumsq);
  float inv_rms = rsqrtf(total * INV_H + EPS);

  const __nv_bfloat16* wptr = w + tid * ELEMS_PER_THREAD;
  __nv_bfloat16* yptr = y + base;

#pragma unroll
  for (int i = 0; i < ELEMS_PER_THREAD; i += 2) {
    __nv_bfloat162 bx = *reinterpret_cast<const __nv_bfloat162*>(xptr + i);
    __nv_bfloat162 bw = *reinterpret_cast<const __nv_bfloat162*>(wptr + i);

    float2 fx = __bfloat1622float2(bx);
    float2 fw = __bfloat1622float2(bw);

    float2 fy;
    fy.x = (fx.x * inv_rms) * fw.x;
    fy.y = (fx.y * inv_rms) * fw.y;

    __nv_bfloat162 by = __float22bfloat162_rn(fy);
    *reinterpret_cast<__nv_bfloat162*>(yptr + i) = by;
  }
}

void rmsnorm_h4096_launcher(const void* hidden_states_bf16,
                            const void* weight_bf16,
                            void* output_bf16,
                            int64_t batch_size,
                            cudaStream_t stream) {
  const __nv_bfloat16* x =
      reinterpret_cast<const __nv_bfloat16*>(hidden_states_bf16);
  const __nv_bfloat16* w =
      reinterpret_cast<const __nv_bfloat16*>(weight_bf16);
  __nv_bfloat16* y = reinterpret_cast<__nv_bfloat16*>(output_bf16);

  if (batch_size <= 0) return;

  dim3 block(THREADS, 1, 1);
  dim3 grid((unsigned)batch_size, 1, 1);

  rmsnorm_h4096_kernel<<<grid, block, 0, stream>>>(x, w, y, batch_size);
  CUDA_CHECK(cudaGetLastError());
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>

#include <sstream>
#include <stdexcept>

#include "kernel.h"

static void check_cuda_bf16_contig(const torch::Tensor& t, const char* name) {
  if (!t.defined()) {
    std::ostringstream oss;
    oss << name << " is undefined";
    throw std::invalid_argument(oss.str());
  }
  if (!t.device().is_cuda()) {
    std::ostringstream oss;
    oss << name << " must be a CUDA tensor";
    throw std::invalid_argument(oss.str());
  }
  if (t.dtype() != torch::kBFloat16) {
    std::ostringstream oss;
    oss << name << " must be torch.bfloat16";
    throw std::invalid_argument(oss.str());
  }
  if (!t.is_contiguous()) {
    std::ostringstream oss;
    oss << name << " must be contiguous";
    throw std::invalid_argument(oss.str());
  }
}

torch::Tensor run(torch::Tensor hidden_states, torch::Tensor weight) {
  check_cuda_bf16_contig(hidden_states, "hidden_states");
  check_cuda_bf16_contig(weight, "weight");

  if (hidden_states.dim() != 2) {
    throw std::invalid_argument("hidden_states must be 2D [batch_size, hidden_size]");
  }
  if (weight.dim() != 1) {
    throw std::invalid_argument("weight must be 1D [hidden_size]");
  }

  const int64_t batch_size = hidden_states.size(0);
  const int64_t hidden_size = hidden_states.size(1);

  if (hidden_size != 4096) {
    std::ostringstream oss;
    oss << "hidden_size must be 4096, got " << hidden_size;
    throw std::invalid_argument(oss.str());
  }
  if (weight.size(0) != 4096) {
    std::ostringstream oss;
    oss << "weight must have shape [4096], got [" << weight.size(0) << "]";
    throw std::invalid_argument(oss.str());
  }
  if (weight.device() != hidden_states.device()) {
    throw std::invalid_argument("weight must be on the same CUDA device as hidden_states");
  }

  auto output = torch::empty_like(hidden_states);

  // Use the *current* stream for correct synchronization with PyTorch.
  const int device_index = hidden_states.device().index();
  cudaStream_t stream = at::cuda::getDefaultCUDAStream(device_index).stream();
  stream = at::cuda::getCurrentCUDAStream(device_index).stream();

  rmsnorm_h4096_launcher(hidden_states.data_ptr(),
                         weight.data_ptr(),
                         output.data_ptr(),
                         batch_size,
                         stream);

  cudaError_t err = cudaGetLastError();
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << "CUDA launch error: " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }

  // Keep deterministic error surfacing for the harness.
  err = cudaDeviceSynchronize();
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << "CUDA error after kernel: " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }

  return output;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "rmsnorm_h4096 (CUDA, BF16)",
        py::arg("hidden_states"),
        py::arg("weight"));
}
